VALUES
  ('social-worker-moex-06910', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '社會工作研究方法包括量化研究方法及質性研究方法，各有不同特色，下列的敘述何者正確？', '["量化研究重視研究發現，質性研究不重視研究發現", "量化研究的複製比較困難，質性研究的複製比較簡單", "量化研究需要事先訂定研究步驟，質性研究在資料蒐集之後，逐步形成彈性步驟", "量化研究與質性研究都缺乏通則化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06911', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究人員強調在同一研究中，結合量化和質性研究方法的重要性，發展出一個新的研究類型，稱為「融 合研究法」（mixed methods research），下列那一項不屬於它的觀點？', '["質性研究說明個案情形，量化研究發現提供數據做為佐證", "量化研究發展量表，質性研究深入訪談", "組合量化與質性的研究發現，相互驗證", "量化研究無法完成研究結果，改採用質性研究"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06912', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '李社工師想要瞭解偏遠地區家庭隔代教養問題及其嚴重性，請問這是屬於研究目的的那一類型？', '["探索性（exploration）", "描述性（description）", "解釋性（explanation）", "評估性（evaluation）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06913', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在規劃研究時，從事文獻回顧（literature review）是研究初期相當關鍵的階段。下列有關文獻回顧的描述， 何者正確？', '["可以提供研究問題形成的良好基礎", "為了引導研究方向，因此有爭論的內容應該儘量避免", "研究主題相當大，相關資訊與發展無法有完整描述", "理論與實務仍有差距，無法解答研究實務所有問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06914', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '小典平時對身心障礙者常有不正確的看法，也常引起其他鄰居的不滿，今天恰巧在小典住家旁邊設置身 心障礙庇護中心，訪員詢問小典是否贊成，小典擔心又引起其他鄰居的不滿，勉強回答贊成。請問這是 那一種誤差？', '["順從反應誤差", "社會期望誤差", "回答誤差", "文化誤差"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06915', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '進行研究時，測量方法都被要求應有信度（reliability）和效度（validity），下列有關信度和效度的描述， 何者正確？', '["信度是指測驗結果的一致性或穩定性", "信度比效度更重要", "內容效度涉及採用因素分析方法加以檢驗", "問項或量表具有信度就一定有效度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06916', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關李克特量表（Likert scale）的敘述，下列那一項錯誤？', '["是一種有關態度的測量工具", "測量題目是開放式的問題", "題目回答類型採用標準化方式", "問題設計有方向性和強弱度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
